```python
import fitz  # PyMuPDF
from pathlib import Path
from typing import Optional

def pdf_extract_text(input_path: Path, password: Optional[str] = None) -> str:
    """Extract text from PDF in reading order. Returns empty string on failure."""
    try:
        doc = fitz.open(input_path)
    except Exception:
        return ""

    try:
        if doc.needs_pass and password is None:
            return ""  # Encrypted without password
        if doc.needs_pass:
            if not doc.authenticate(password):
                return ""

        text_parts: list[str] = []
        for page in doc:
            try:
                text = page.get_text("text", sort=True)  # sort=True preserves reading order
                if text.strip():
                    text_parts.append(text)
            except Exception:
                continue  # Skip problematic pages

        return "\n\n".join(text_parts).strip()
    finally:
        doc.close()
```

**Key points for WCAG compliance**:
- `sort=True` is critical — it ensures text comes out in logical reading order (not just visual page order), which helps screen readers.
- This does **not** extract structured elements (headings, lists) — for that, use `page.get_text("blocks")` or `page.get_text("dict")` and post-process.
- Encrypted PDFs are handled gracefully: returns empty string rather than raising.

